     1→//! High-performance resampling methods for statistical inference
     2→//!
     3→//! This crate provides parallel implementations of bootstrap, jackknife,
     4→//! and other resampling techniques optimized for large datasets.
     5→
     6→#![forbid(unsafe_code)]
     7→#![warn(missing_docs)]
     8→
     9→use ndarray::{Array1, Array2, ArrayView1, ArrayView2, Axis};
    10→use rand::{thread_rng, Rng, SeedableRng};
    11→use rayon::prelude::*;
    12→use std::sync::Arc;
    13→
    14→/// Resampling errors
    15→#[derive(thiserror::Error, Debug)]
    16→pub enum ResampleError {
    17→    /// Invalid sample size
    18→    #[error("Invalid sample size: {0}")]
    19→    InvalidSampleSize(usize),
    20→    /// Insufficient data
    21→    #[error("Insufficient data: need at least {0} observations")]
    22→    InsufficientData(usize),
    23→}
    24→
    25→/// Configuration for bootstrap resampling
    26→#[derive(Debug, Clone)]
    27→pub struct BootstrapConfig {
    28→    /// Number of bootstrap samples
    29→    pub n_samples: usize,
    30→    /// Random seed for reproducibility
    31→    pub seed: Option<u64>,
    32→    /// Whether to use parallel processing
    33→    pub parallel: bool,
    34→}
    35→
    36→impl Default for BootstrapConfig {
    37→    fn default() -> Self {
    38→        Self {
    39→            n_samples: 1000,
    40→            seed: None,
    41→            parallel: true,
    42→        }
    43→    }
    44→}
    45→
    46→/// Bootstrap result containing statistics from all resamples
    47→#[derive(Debug)]
    48→pub struct BootstrapResult {
    49→    /// Bootstrap statistics for each sample
    50→    pub statistics: Array2<f64>,
    51→    /// Bootstrap estimates (mean of statistics)
    52→    pub estimates: Array1<f64>,
    53→    /// Standard errors (std of statistics)
    54→    pub std_errors: Array1<f64>,
    55→    /// Confidence intervals (if computed)
    56→    pub confidence_intervals: Option<Array2<f64>>,
    57→}
    58→
    59→/// Trait for statistics that can be computed on resampled data
    60→pub trait BootstrapStatistic {
    61→    /// Compute the statistic for given data
    62→    fn compute(&self, x: ArrayView2<f64>, y: ArrayView1<f64>) -> Array1<f64>;
    63→
    64→    /// Number of statistics this function returns
    65→    fn n_stats(&self) -> usize;
    66→}
    67→
    68→/// Perform bootstrap resampling with parallel processing
    69→///
    70→/// This function implements case resampling (resampling rows of the data matrix)
    71→/// with optional parallelization for performance on large datasets.
    72→///
    73→/// # Arguments
    74→/// * `x` - Predictor matrix (n_observations × n_predictors)
    75→/// * `y` - Response vector (n_observations)
    76→/// * `statistic` - Function to compute statistics on resampled data
    77→/// * `config` - Bootstrap configuration
    78→///
    79→/// # Returns
    80→/// * `BootstrapResult` containing bootstrap distribution and estimates
    81→pub fn bootstrap<S>(
    82→    x: ArrayView2<f64>,
    83→    y: ArrayView1<f64>,
    84→    statistic: S,
    85→    config: Option<BootstrapConfig>,
    86→) -> Result<BootstrapResult, ResampleError>
    87→where
    88→    S: BootstrapStatistic + Sync + Send,
    89→{
    90→    let config = config.unwrap_or_default();
    91→    let n_obs = x.nrows();
    92→    let n_stats = statistic.n_stats();
    93→
    94→    if n_obs == 0 {
    95→        return Err(ResampleError::InsufficientData(1));
    96→    }
    97→
    98→    if config.n_samples == 0 {
    99→        return Err(ResampleError::InvalidSampleSize(config.n_samples));
   100→    }
   101→
   102→    // Set random seed if provided
   103→    if let Some(seed) = config.seed {
   104→        // Note: We'll handle seeding in the parallel case differently
   105→        let _ = seed;
   106→    }
   107→
   108→    let statistic = Arc::new(statistic);
   109→
   110→    // Parallel bootstrap sampling
   111→    let bootstrap_stats: Vec<Array1<f64>> = if config.parallel {
   112→        (0..config.n_samples)
   113→            .into_par_iter()
   114→            .map(|_| {
   115→                let mut rng = thread_rng();
   116→                let indices: Vec<usize> = (0..n_obs).map(|_| rng.gen_range(0..n_obs)).collect();
   117→
   118→                // Create bootstrap sample
   119→                let x_boot = x.select(Axis(0), &indices);
   120→                let y_boot = y.select(Axis(0), &indices);
   121→
   122→                // Compute statistic
   123→                statistic.compute(x_boot.view(), y_boot.view())
   124→            })
   125→            .collect()
   126→    } else {
   127→        // Sequential version for reproducible results with seed
   128→        let mut rng = if let Some(seed) = config.seed {
   129→            rand::rngs::StdRng::seed_from_u64(seed)
   130→        } else {
   131→            rand::rngs::StdRng::from_entropy()
   132→        };
   133→
   134→        (0..config.n_samples)
   135→            .map(|_| {
   136→                let indices: Vec<usize> = (0..n_obs).map(|_| rng.gen_range(0..n_obs)).collect();
   137→
   138→                // Create bootstrap sample
   139→                let x_boot = x.select(Axis(0), &indices);
   140→                let y_boot = y.select(Axis(0), &indices);
   141→
   142→                // Compute statistic
   143→                statistic.compute(x_boot.view(), y_boot.view())
   144→            })
   145→            .collect()
   146→    };
   147→
   148→    // Combine results into matrix
   149→    let mut statistics = Array2::zeros((config.n_samples, n_stats));
   150→    for (i, stat) in bootstrap_stats.iter().enumerate() {
   151→        statistics.row_mut(i).assign(stat);
   152→    }
   153→
   154→    // Compute estimates and standard errors
   155→    let estimates = statistics.mean_axis(Axis(0)).unwrap();
   156→    let std_errors = statistics.std_axis(Axis(0), 0.0);
   157→
   158→    Ok(BootstrapResult {
   159→        statistics,
   160→        estimates,
   161→        std_errors,
   162→        confidence_intervals: None,
   163→    })
   164→}
   165→
   166→/// Compute confidence intervals from bootstrap distribution
   167→pub fn bootstrap_confidence_intervals(
   168→    result: &mut BootstrapResult,
   169→    alpha: f64,
   170→) -> Result<(), ResampleError> {
   171→    let _confidence_level = 1.0 - alpha;
   172→    let lower_percentile = alpha / 2.0;
   173→    let upper_percentile = 1.0 - alpha / 2.0;
   174→
   175→    let n_stats = result.statistics.ncols();
   176→    let mut intervals = Array2::zeros((n_stats, 2));
   177→
   178→    for j in 0..n_stats {
   179→        let mut values: Vec<f64> = result.statistics.column(j).to_vec();
   180→        values.sort_by(|a, b| a.partial_cmp(b).unwrap());
   181→
   182→        let n = values.len();
   183→        let lower_idx = ((n as f64) * lower_percentile).floor() as usize;
   184→        let upper_idx = ((n as f64) * upper_percentile).ceil() as usize - 1;
   185→
   186→        intervals[[j, 0]] = values[lower_idx.min(n - 1)];
   187→        intervals[[j, 1]] = values[upper_idx.min(n - 1)];
   188→    }
   189→
   190→    result.confidence_intervals = Some(intervals);
   191→    Ok(())
   192→}
   193→
   194→/// Jackknife resampling (leave-one-out)
   195→///
   196→/// Computes the jackknife estimate by systematically leaving out one observation
   197→/// at a time and computing the statistic on the remaining data.
   198→pub fn jackknife<S>(
   199→    x: ArrayView2<f64>,
   200→    y: ArrayView1<f64>,
   201→    statistic: S,
   202→) -> Result<BootstrapResult, ResampleError>
   203→where
   204→    S: BootstrapStatistic + Sync + Send,
   205→{
   206→    let n_obs = x.nrows();
   207→    let n_stats = statistic.n_stats();
   208→
   209→    if n_obs <= 1 {
   210→        return Err(ResampleError::InsufficientData(2));
   211→    }
   212→
   213→    let statistic = Arc::new(statistic);
   214→
   215→    // Parallel jackknife computation
   216→    let jackknife_stats: Vec<Array1<f64>> = (0..n_obs)
   217→        .into_par_iter()
   218→        .map(|i| {
   219→            // Create indices excluding observation i
   220→            let indices: Vec<usize> = (0..n_obs).filter(|&idx| idx != i).collect();
   221→
   222→            // Create jackknife sample
   223→            let x_jack = x.select(Axis(0), &indices);
   224→            let y_jack = y.select(Axis(0), &indices);
   225→
   226→            // Compute statistic
   227→            statistic.compute(x_jack.view(), y_jack.view())
   228→        })
   229→        .collect();
   230→
   231→    // Combine results into matrix
   232→    let mut statistics = Array2::zeros((n_obs, n_stats));
   233→    for (i, stat) in jackknife_stats.iter().enumerate() {
   234→        statistics.row_mut(i).assign(stat);
   235→    }
   236→
   237→    // Compute jackknife estimates and standard errors
